mapper.select:
		select count(id) from wf_task 

			left join wf_task_actor ta on ta.task_id = id



                instance_Id = #{request.instanceId}


                and id not in

                    #{excludedId}



                and ta.actor_Id in

                    #{operator}



                and task_Name in

                    #{name}



                and create_Time >= #{request.createTimeStart}


                and create_Time <= #{request.createTimeEnd}

		select id, instance_Id, task_Name, display_Name, task_Type, perform_Type, operator, create_Time, finish_Time,
		expire_Time, action_Url, parent_Task_Id, variable, version 
		from wf_task 

			left join wf_task_actor ta on ta.task_id = id



                instance_Id = #{request.instanceId}


                and id not in

                    #{excludedId}



                and ta.actor_Id in

                    #{operator}



                and task_Name in

                    #{name}



                and create_Time >= #{request.createTimeStart}


                and create_Time <= #{request.createTimeEnd}



            order by #{request.sortString}

		limit #{rowOffset}, #{request.pageSize}
